                <DropdownMenuItem onClick={() => navigate("/playbooks")} className="cursor-pointer">
                  <BookOpen className="mr-2 h-4 w-4" />
                  Playbooks
                </DropdownMenuItem>
                <DropdownMenuSeparator />
