                <Button variant="outline" size="sm" onClick={loadLastWeek} disabled={isLoadingHistory} data-testid="btn-load-last-week">
                  {isLoadingHistory ? <Loader2 className="h-4 w-4 animate-spin" /> : <History className="h-4 w-4 mr-1" />}
