              {getAlertBadge(parseInt(alertsInputs.avgEntreeTime) || 0, 15, 18, "Entr\u00e9es")}
              <Badge
                className={alertsInputs.windowHolding
                  ? "bg-red-500/15 text-red-700 dark:text-red-400 border-red-500/30"
