              </Select>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label htmlFor="seatCount">Seat Count</Label>
                <Input
                  id="seatCount"
                  type="number"
                  value={formData.seatCount || ''}
                  onChange={(e) => updateField('seatCount', parseInt(e.target.value) || undefined)}
