            </CardContent>
          </Card>

          <Collapsible open={dangerZoneOpen} onOpenChange={setDangerZoneOpen}>
            <Card className={dangerZoneOpen ? "border-destructive/50" : ""}>
              <CollapsibleTrigger asChild>
                <CardHeader className="cursor-pointer">
