import { sql } from "drizzle-orm";
import { index, jsonb, pgTable, timestamp, varchar } from "drizzle-orm/pg-core";

// Session storage table.
// (IMPORTANT) This table is mandatory for Replit Auth, don't drop it.
export const sessions = pgTable(
  "sessions",
  {
    sid: varchar("sid").primaryKey(),
    sess: jsonb("sess").notNull(),
    expire: timestamp("expire").notNull(),
  },
  (table) => [index("IDX_session_expire").on(table.expire)]
);

// User roles for role-based access control
export const USER_ROLES = {
  OWNER: "owner",
  GENERAL_MANAGER: "general_manager",
  MANAGER: "manager",
} as const;

export type UserRole = typeof USER_ROLES[keyof typeof USER_ROLES];

// User storage table.
// (IMPORTANT) This table is mandatory for Replit Auth, don't drop it.
export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  email: varchar("email").unique(),
  firstName: varchar("first_name"),
  lastName: varchar("last_name"),
  phone: varchar("phone"),
  address: varchar("address"),
  restaurantName: varchar("restaurant_name"),
  role: varchar("role").default("owner"), // owner, general_manager, manager
  profileImageUrl: varchar("profile_image_url"),
  stripeCustomerId: varchar("stripe_customer_id"),
  stripeSubscriptionId: varchar("stripe_subscription_id"),
  subscriptionStatus: varchar("subscription_status"),
  subscriptionTier: varchar("subscription_tier").default("free"),
  isAdmin: varchar("is_admin").default("false"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const SUBSCRIPTION_TIERS = {
  FREE: "free",
  BASIC: "basic",
  PRO: "pro",
} as const;

export type SubscriptionTier = typeof SUBSCRIPTION_TIERS[keyof typeof SUBSCRIPTION_TIERS];

export const FREE_DOMAIN_SLUGS = ["leadership", "kitchen", "crisis"] as const;

export type UpsertUser = typeof users.$inferInsert;
export type User = typeof users.$inferSelect;

