            ) : (
              <Check className="h-8 w-8 text-primary" />
            )}
          </div>
          <CardTitle className="text-2xl">Welcome to Pro!</CardTitle>
          <CardDescription>
            Your subscription is now active. You have full access to Restaurant Consultant Pro.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Button 
            className="w-full" 
            size="lg"
            onClick={() => setLocation("/")}
            data-testid="btn-get-started"
          >
            Get Started
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

