    alcohol: true,
    tipPolicy: true,
  });

  const { data: settings, isLoading } = useQuery<HandbookSettings | null>({
    queryKey: ["/api/handbook-settings"],
  });

  const [formData, setFormData] = useState<Partial<HandbookSettings>>({
