                page-break-before: always;
              }
              .no-break {
                page-break-inside: avoid;
              }
            }
            .print-header {
              text-align: center;
              margin-bottom: 2em;
              padding-bottom: 1em;
              border-bottom: 2px solid #333;
            }
            .print-header h1 {
