      let financialContext = "";
      let documents: any[] = [];

      if (documentId) {
        const doc = await storage.getFinancialDocument(documentId, userId);
        if (doc) {
          documents = [doc];
          const extract = await storage.getFinancialExtract(documentId);
          if (extract) {
