                    </div>
                    <div>
                      <Label>Priority</Label>
                      <Select value={newAnnouncement.priority} onValueChange={(v) => setNewAnnouncement(a => ({ ...a, priority: v }))}>
                        <SelectTrigger className="mt-1" data-testid="select-announcement-priority">
