import { Check, X, Loader2, ChefHat, ArrowLeft, Crown, Star, Zap } from "lucide-react";
import { Link, useLocation } from "wouter";

const tiers = [
  {
    id: "free",
    name: "Free",
    icon: Zap,
    description: "Get started with core tools",
    monthlyPrice: 0,
    annualPrice: 0,
