                      </li>
                    ))}
                  </ul>

                  <Button
                    className="w-full"
                    variant={isPopular ? "default" : btnState.variant}
                    disabled={btnState.disabled || isCheckingThisTier}
                    onClick={() => {
                      if (tier.id === "free") {
                        if (!user) startLogin();
                        else if (subscriptionTier !== "free") openPortal();
                        else setLocation("/");
                      } else {
                        handleCheckout(tier.id);
